-- TreatmentRankings: Table: TreatmentRankings — one row per treatment-pair comparison within a study. Derives the pooled winner, the per-stratum winner, and the IsReversal boolean. The paradox emerges here as a derived fact: IsReversal is true when the pooled winner and the per-stratum winner disagree.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS treatment_rankings (
  treatment_ranking_id                TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-A-vs-B).
);
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS study TEXT;                                 -- FK to the parent Study.
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS treatment_a TEXT;                           -- Label for the first treatment in the comparison (matches Treatments.TreatmentLabel).
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS treatment_b TEXT;                           -- Label for the second treatment in the comparison.
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS adjustment_rationale TEXT;                  -- Human-authored note explaining why AdjustmentAppropriate is TRUE or FALSE for this study. Covers mediator/collider hazards, contested causal roles, and cases where geometric correction is valid but causal interpretation is uncertain.
COMMENT ON TABLE treatment_rankings IS 'Table: TreatmentRankings — one row per treatment-pair comparison within a study. Derives the pooled winner, the per-stratum winner, and the IsReversal boolean. The paradox emerges here as a derived fact: IsReversal is true when the pooled winner and the per-stratum winner disagree.';
COMMENT ON COLUMN treatment_rankings.treatment_ranking_id IS 'Unique slug (e.g. kidney-1986-A-vs-B).';
COMMENT ON COLUMN treatment_rankings.study IS 'FK to the parent Study.';
COMMENT ON COLUMN treatment_rankings.treatment_a IS 'Label for the first treatment in the comparison (matches Treatments.TreatmentLabel).';
COMMENT ON COLUMN treatment_rankings.treatment_b IS 'Label for the second treatment in the comparison.';
COMMENT ON COLUMN treatment_rankings.adjustment_rationale IS 'Human-authored note explaining why AdjustmentAppropriate is TRUE or FALSE for this study. Covers mediator/collider hazards, contested causal roles, and cases where geometric correction is valid but causal interpretation is uncertain.';

-- ----------------------------------------------------------------------------
-- InvariantChecks: Table: InvariantChecks — one row per algebraic invariant that must hold across the full validation set. PassCount and FailCount are populated by 05b-customize-data.sql from live queries against vw_treatment_rankings. Any FailCount > 0 is a build-breaking bug.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS invariant_checks (
  invariant_check_id                  TEXT                 PRIMARY KEY          -- Unique slug for this invariant (e.g. inv-balanced-alloc).
);
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS algebraic_statement TEXT;                     -- The mathematical assertion in compact symbolic form.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS natural_language TEXT;                        -- Plain-English statement of what property must hold and why it is an invariant of the model.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS source_table TEXT;                            -- The DAG table whose rows are checked (TreatmentRankings or StratumSummaries).
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS filter_expression TEXT;                       -- Condition selecting the universe of rows this invariant applies to. Empty means all rows.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS assertion_expression TEXT;                    -- The per-row condition that must be TRUE for every row in scope.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS sql_filter TEXT;                              -- Optional SQL WHERE clause that selects the universe of rows in scope for this invariant (e.g. distortion_type = 'D'). Empty string means all rows.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS sql_assertion TEXT;                           -- The SQL WHERE clause (without WHERE keyword) that counts PASSING rows from vw_treatment_rankings for this invariant. Used by run_invariant_checks() to evaluate each assertion dynamically from the rulebook table.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS pass_count INTEGER;                           -- Rows where the invariant holds. Populated by 05b-customize-data.sql from a live query against vw_treatment_rankings.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS fail_count INTEGER;                           -- Rows where the invariant is violated. Any FailCount > 0 is a build-breaking bug.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS severity TEXT;                                -- critical | warning — critical means any FailCount > 0 is a build-breaking bug.
COMMENT ON TABLE invariant_checks IS 'Table: InvariantChecks — one row per algebraic invariant that must hold across the full validation set. PassCount and FailCount are populated by 05b-customize-data.sql from live queries against vw_treatment_rankings. Any FailCount > 0 is a build-breaking bug.';
COMMENT ON COLUMN invariant_checks.invariant_check_id IS 'Unique slug for this invariant (e.g. inv-balanced-alloc).';
