-- InstrumentSpec: Table: InstrumentSpec — the complete specification of the Simpson's Paradox classification instrument. One row per component: required input fields, derived coordinates, classification outputs, and adapter requirements. Every row is machine-verifiable against the 16 hydrated studies. This table is the distillation of loops 1–25 into a reusable tool.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS instrument_spec (
  spec_id                             TEXT                 PRIMARY KEY          -- Unique identifier for this instrument component.
);
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS component_type TEXT;                           -- input | derived | classification | adapter-requirement
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS field_name TEXT;                               -- The field or variable name in the DAG.
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS data_type TEXT;                                -- integer | decimal | boolean | string | categorical
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS source_table TEXT;                             -- The DAG table where this field is computed or stored.
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS formula TEXT;                                  -- The ERB formula or derivation rule for this component.
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS natural_language TEXT;                         -- Plain-English statement of what this component represents or requires.
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS adapter_note TEXT;                             -- What a researcher must supply or verify to satisfy this component when hydrating a new study.
COMMENT ON TABLE instrument_spec IS 'Table: InstrumentSpec — the complete specification of the Simpson''s Paradox classification instrument. One row per component: required input fields, derived coordinates, classification outputs, and adapter requirements. Every row is machine-verifiable against the 16 hydrated studies. This table is the distillation of loops 1–25 into a reusable tool.';
COMMENT ON COLUMN instrument_spec.spec_id IS 'Unique identifier for this instrument component.';
COMMENT ON COLUMN instrument_spec.component_type IS 'input | derived | classification | adapter-requirement';
COMMENT ON COLUMN instrument_spec.field_name IS 'The field or variable name in the DAG.';
COMMENT ON COLUMN instrument_spec.data_type IS 'integer | decimal | boolean | string | categorical';
COMMENT ON COLUMN instrument_spec.source_table IS 'The DAG table where this field is computed or stored.';
COMMENT ON COLUMN instrument_spec.formula IS 'The ERB formula or derivation rule for this component.';
COMMENT ON COLUMN instrument_spec.natural_language IS 'Plain-English statement of what this component represents or requires.';
COMMENT ON COLUMN instrument_spec.adapter_note IS 'What a researcher must supply or verify to satisfy this component when hydrating a new study.';

